INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000001', 'US Survey Foot vs International Foot', 'The US survey foot = 1200/3937 m ≈ 0.30480061 m; the international foot = 0.3048 m exactly. They differ by ~2 ppm, which becomes significant over long distances and in State Plane Coordinates.', 'One is defined exactly as 0.3048 m.', NULL, NULL, NULL, ARRAY['units','foot','conversion','state plane']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000002', 'Gunter''s Chain', 'A traditional survey unit: 1 chain = 66 feet = 100 links. 80 chains = 1 mile; 10 square chains = 1 acre.', '66 feet.', NULL, NULL, NULL, ARRAY['chain','links','units']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000003', 'Acre', 'A unit of area equal to 43,560 square feet, or 10 square chains.', '43,560 ft².', NULL, NULL, NULL, ARRAY['acre','area','units']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000004', 'Accuracy vs Precision', 'Accuracy is how close a measurement is to the true value; precision is how closely repeated measurements agree with one another. A set can be precise but inaccurate.', 'One compares to truth, the other to itself.', NULL, NULL, NULL, ARRAY['accuracy','precision','error']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000005', 'Gross Error (Blunder)', 'A mistake caused by carelessness — misreading, transposing digits, mis-recording. It is not random and must be detected and removed from the data set.', 'A human mistake, not a natural error.', NULL, NULL, NULL, ARRAY['blunder','gross error','mistake']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000006', 'Systematic Error', 'An error that follows a physical law, keeping the same sign and magnitude under the same conditions (e.g., a tape that is too long). It can be modeled and corrected.', 'Same conditions → same error; correctable.', NULL, NULL, NULL, ARRAY['systematic','error','correction']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000007', 'Random Error', 'A small, unavoidable error that follows the normal distribution — equally likely to be positive or negative. It cannot be eliminated but is reduced by repetition and averaging.', 'Follows the bell curve; reduced by averaging.', NULL, NULL, NULL, ARRAY['random','error','normal']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000008', 'Most Probable Value', 'For a set of equally weighted, independent observations, the most probable value is the arithmetic mean: x̄ = Σxᵢ / n.', 'It is just the mean.', NULL, NULL, NULL, ARRAY['most probable value','mean','average']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000009', 'Residual', 'The difference between an individual observation and the most probable value (mean): v = xᵢ − x̄. Residuals are used to compute standard deviation.', 'v = xᵢ − x̄.', NULL, NULL, NULL, ARRAY['residual','v','mean']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000010', 'Sample Standard Deviation', 'A measure of the spread of observations: σ = √( Σv² / (n − 1) ), where v = xᵢ − x̄. The (n − 1) denominator applies to a sample.', 'Divide the sum of squared residuals by (n − 1).', 'Then take the square root.', NULL, NULL, ARRAY['standard deviation','sigma','spread']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000011', 'Standard Error of the Mean', 'The uncertainty of the computed mean: σ_m = σ / √n. Taking more observations shrinks it by the square root of n.', 'Divide σ by √n.', NULL, NULL, NULL, ARRAY['standard error','mean','sigma_m']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000012', 'Error Propagation — Sum', 'When independent random errors add, they combine in quadrature: E_sum = √( E₁² + E₂² + … + Eₙ² ).', 'Root-sum-square of the individual errors.', NULL, NULL, NULL, ARRAY['error propagation','sum','quadrature']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000013', 'Error Propagation — Series', 'For n measurements each carrying the same random error E (e.g., laying a tape n times), the total error is E_series = E·√n.', 'E times the square root of n.', NULL, NULL, NULL, ARRAY['error propagation','series','taping']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000014', 'Relative Precision', 'A ratio expressing precision as 1 : (distance / error) — e.g., an error of 0.1 ft over 500 ft is 1:5000. Larger second number = higher precision.', 'Express as 1 : (distance ÷ error).', NULL, NULL, NULL, ARRAY['relative precision','ratio','accuracy ratio']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000015', '68-95-99.7 Rule', 'For normally distributed data, about 68% of values fall within ±1σ of the mean, ~95% within ±2σ, and ~99.7% within ±3σ.', 'One, two, and three standard deviations.', NULL, NULL, NULL, ARRAY['normal distribution','empirical rule','sigma']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000016', 'Weighted Mean', 'When observations have different reliabilities, the best estimate is x̄_w = Σ(wᵢ·xᵢ) / Σwᵢ, where each weight is inversely proportional to variance: wᵢ ∝ 1/σᵢ².', 'Weight each value, then average.', 'Weight ∝ 1/σ².', NULL, NULL, ARRAY['weighted mean','weight','variance']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000017', 'Weight (in Adjustment)', 'A number expressing the relative reliability of an observation. Weight is inversely proportional to variance: w ∝ 1/σ². More precise observations get more weight.', 'Inversely proportional to variance.', NULL, NULL, NULL, ARRAY['weight','variance','adjustment']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000018', 'Significant Figures', 'The digits in a number that carry real meaning; the last significant figure is the estimated/uncertain one. They govern how results are rounded so precision is not overstated.', 'The last one is the uncertain digit.', NULL, NULL, NULL, ARRAY['significant figures','rounding','precision']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000019', 'Confidence Interval', 'A range that likely contains the true value: x̄ ± Z·σ_m, where Z is the standard-normal multiplier for the confidence level (Z = 1.6449 at 90%, 1.9600 at 95%).', 'Mean ± Z·(standard error).', NULL, NULL, NULL, ARRAY['confidence interval','Z','probability']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000020', '90% and 95% Error (Z-values)', 'Common probable-error multipliers of the standard deviation: the 90% error = 1.6449σ and the 95% error = 1.9600σ.', '≈1.645 and ≈1.96.', NULL, NULL, NULL, ARRAY['Z value','90 percent','95 percent','probable error']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:f5000001-0000-0000-0000-000000000001', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000001', 'Differential Leveling (HI Method)', 'Determining the elevation of points by reading a rod through a level. The instrument height is found from a known point, then unknown elevations are read from it: HI = Elev + BS, Elev = HI − FS.', 'Backsight up to HI, foresight down to the point.', NULL, NULL, NULL, ARRAY['differential leveling','HI','elevation']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000002', 'Benchmark (BM)', 'A permanent, stable point of known elevation used as a reference/starting point for leveling.', 'Permanent point of known elevation.', NULL, NULL, NULL, ARRAY['benchmark','BM','datum']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000003', 'Turning Point (TP)', 'A temporary point on which a foresight is taken and then the next backsight, allowing the level to be moved forward while carrying elevation along the line.', 'Both an FS and the next BS are taken on it.', NULL, NULL, NULL, ARRAY['turning point','TP','leveling']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000004', 'Backsight (BS)', 'A rod reading taken on a point of known elevation. It is added to that elevation to obtain the Height of Instrument (the "plus sight").', 'Added to elevation → HI.', NULL, NULL, NULL, ARRAY['backsight','BS','plus sight']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000005', 'Foresight (FS)', 'A rod reading on a point of unknown elevation. It is subtracted from the Height of Instrument to get that point’s elevation (the "minus sight").', 'Subtracted from HI → elevation.', NULL, NULL, NULL, ARRAY['foresight','FS','minus sight']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000006', 'Height of Instrument (HI)', 'The elevation of the instrument’s line of sight: HI = Elev_BM + BS. Point elevations are then HI − FS.', 'HI = known elevation + backsight.', NULL, NULL, NULL, ARRAY['height of instrument','HI']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000007', 'Elevation Difference (multi-setup)', 'Over a run with several instrument setups, the net elevation change equals the sum of backsights minus the sum of foresights: ΔElev = ΣBS − ΣFS.', 'Sum of BS minus sum of FS.', NULL, NULL, NULL, ARRAY['elevation difference','sum','leveling']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000008', 'Arithmetic Check', 'A bookkeeping check on a level run: the final minus initial elevation must equal ΣBS − ΣFS. It verifies the math, not the field work.', 'Elev_last − Elev_first = ΣBS − ΣFS.', NULL, NULL, NULL, ARRAY['arithmetic check','leveling','bookkeeping']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000009', 'NAVD88', 'The North American Vertical Datum of 1988 — the standard vertical datum for orthometric heights (elevations) in North America.', 'The standard modern vertical datum.', NULL, NULL, NULL, ARRAY['NAVD88','datum','vertical']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000010', 'Curvature & Refraction Correction', 'Earth curvature makes a distant rod read too high; atmospheric refraction partly offsets it. The combined correction is C_R = 0.0206·F², with F the sight distance in thousands of feet.', '0.0206·F² (F in thousands of ft).', NULL, NULL, NULL, ARRAY['curvature','refraction','correction']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000011', 'Trigonometric Leveling', 'Finding elevation difference from a measured distance and vertical/zenith angle: ΔElev = S·sin(V) = d·tan(V), then add instrument height and subtract rod/target height (+ hi − hr).', 'Slope distance × sin(vertical angle).', NULL, NULL, NULL, ARRAY['trigonometric leveling','vertical angle','elevation']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000012', 'Collimation Error', 'The line of sight is not truly horizontal (not parallel to the leveling axis), so readings are biased with distance. It is detected and quantified by the two-peg test.', 'Line of sight not level; found by the two-peg test.', NULL, NULL, NULL, ARRAY['collimation','error','two-peg']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000013', 'Two-Peg Test', 'A field check for collimation error: compare rod readings taken with the instrument midway between two pegs (errors cancel) to readings taken near one peg (error shows), then solve for the collimation error.', 'Midpoint setup vs end setup.', NULL, NULL, NULL, ARRAY['two-peg test','collimation','calibration']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000014', 'Loop Misclosure', 'The error in a level loop/line: Misclosure = (ΣBS − ΣFS) − (Elev_known_end − Elev_known_start). It is distributed among setups (often by distance) to adjust elevations.', 'Measured Δ minus known Δ.', NULL, NULL, NULL, ARRAY['misclosure','loop','adjustment']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000015', 'Reciprocal Leveling', 'Leveling across a wide obstacle (e.g., a river) by taking readings in both directions so curvature, refraction, and collimation cancel: Δh = ½[(a₁ − b₁) + (a₂ − b₂)].', 'Average the two-direction differences.', NULL, NULL, NULL, ARRAY['reciprocal leveling','river','obstacle']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000016', 'Three-Wire Leveling', 'Reading the upper, middle, and lower stadia wires; the mean = (U + M + L)/3 gives a checked rod reading, and the wire interval gives the sight distance for balancing.', 'Average of three stadia-wire readings.', NULL, NULL, NULL, ARRAY['three-wire','stadia','leveling']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000017', 'Balancing BS/FS Distances', 'Keeping backsight and foresight distances equal at each setup cancels collimation error, earth curvature, and refraction — a core good-practice of precise leveling.', 'Equal sight lengths cancel systematic errors.', NULL, NULL, NULL, ARRAY['balancing','backsight','foresight']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000018', 'Profile Leveling', 'Taking a series of elevations at intervals along a line (e.g., a route centerline) to plot a vertical profile of the ground.', 'Elevations along a line → a profile.', NULL, NULL, NULL, ARRAY['profile leveling','centerline','profile']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000019', 'Curvature-Only Correction', 'The elevation error from earth curvature alone (no refraction) on a rod reading: C = 0.0240·F², with F in thousands of feet.', '0.0240·F² (F in thousands of ft).', NULL, NULL, NULL, ARRAY['curvature','correction']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000020', 'Datum (Vertical)', 'The reference surface from which elevations are measured (e.g., NAVD88, or mean sea level for older NGVD29). All benchmark elevations tie to a datum.', 'The zero surface for elevations.', NULL, NULL, NULL, ARRAY['datum','vertical','elevation']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:f5000002-0000-0000-0000-000000000002', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000001', 'Temperature (Thermal) Tape Correction', 'A steel tape lengthens when hotter than its 68°F standard: Ct = 0.00000645·(T − 68)·L (per °F). Add when warmer, subtract when cooler.', 'Coefficient 6.45×10⁻⁶ per °F.', NULL, NULL, NULL, ARRAY['temperature','tape correction','thermal']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000002', 'Sag Correction', 'An unsupported tape sags into a catenary and reads too long. The correction is always negative: Cs = −w²·L³ / (24·P²), with w the weight per unit length and P the pull.', 'Always subtract; depends on weight and pull.', NULL, NULL, NULL, ARRAY['sag','tape correction','catenary']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000003', 'Tension (Pull) Correction', 'Applying more pull than standard stretches the tape: Cp = (P − P0)·L / (A·E), where A is cross-sectional area and E is the modulus of elasticity.', 'Extra pull → longer tape.', NULL, NULL, NULL, ARRAY['tension','pull','tape correction']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000004', 'Slope (Grade) Correction', 'Reduces a length measured along a slope to horizontal: Ch ≈ −h² / (2L), where h is the elevation difference over the tape length L.', 'Subtract h²/(2L).', NULL, NULL, NULL, ARRAY['slope','correction','horizontal distance']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000005', 'Standardization Correction', 'Corrects for a tape whose true length differs from its nominal length (verified against a standard) — a "too long/too short" per-tape-length adjustment applied to every measurement.', 'Fixes a tape that is not its marked length.', NULL, NULL, NULL, ARRAY['standardization','tape correction','calibration']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000006', 'EDM (Electronic Distance Measurement)', 'Measures distance from the phase shift / travel time of a modulated light or infrared beam reflected from a prism (or a surface, reflectorless).', 'Distance from a light/IR beam.', NULL, NULL, NULL, ARRAY['EDM','distance','instrument']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000007', 'EDM Error (constant + ppm)', 'EDM uncertainty has two parts: a fixed instrument constant plus a distance-proportional term, e = ±(a mm + b·ppm·D). The ppm part grows with the line length.', 'A fixed part + a per-km part.', NULL, NULL, NULL, ARRAY['EDM','error','ppm']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000008', 'Total Station', 'An instrument combining an EDM and an electronic theodolite to measure distances and horizontal/vertical angles and compute coordinates directly.', 'EDM + electronic theodolite.', NULL, NULL, NULL, ARRAY['total station','instrument']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000009', 'Zenith Angle', 'A vertical angle measured down from the upward vertical: straight up = 0°, the horizon = 90°, straight down = 180°. Used in H = S·sin(Z).', 'Zero points straight up.', NULL, NULL, NULL, ARRAY['zenith angle','vertical']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000010', 'Vertical Angle', 'An angle measured up (+) or down (−) from the horizontal plane. Related to the zenith angle by V = 90° − Z.', 'Measured from horizontal, ± .', NULL, NULL, NULL, ARRAY['vertical angle','horizontal']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000011', 'Direct & Reverse (Face L / Face R)', 'Observing an angle in both telescope positions and averaging cancels instrumental errors (collimation, trunnion-axis, vertical-index).', 'Average both faces to cancel errors.', NULL, NULL, NULL, ARRAY['direct reverse','face left','face right']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000012', 'Azimuth', 'A direction measured clockwise from north, 0°–360°. Unambiguous — no quadrant letters needed.', 'Clockwise from north, 0–360°.', NULL, NULL, NULL, ARRAY['azimuth','direction']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000013', 'Bearing', 'A direction given as an acute angle (0°–90°) from north or south toward east or west, e.g. N 45° E. Four quadrants.', 'Acute angle from N or S toward E or W.', NULL, NULL, NULL, ARRAY['bearing','quadrant','direction']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000014', 'Back-Azimuth', 'The reverse of a direction: Back-Az = Az ± 180° (add if Az < 180°, subtract if Az ≥ 180°).', 'Azimuth ± 180°.', NULL, NULL, NULL, ARRAY['back-azimuth','reverse direction']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000015', 'Back-Bearing', 'The reverse of a bearing: the same numeric angle with both quadrant letters flipped (N↔S and E↔W). N 30° E becomes S 30° W.', 'Flip both letters, keep the angle.', NULL, NULL, NULL, ARRAY['back-bearing','reverse']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000016', 'DMS ↔ Decimal Degrees', 'Convert degrees-minutes-seconds to decimal: dd = D + M/60 + S/3600. Reverse by extracting whole degrees, then minutes from the remainder, then seconds.', 'Minutes/60 + seconds/3600.', NULL, NULL, NULL, ARRAY['DMS','decimal degrees','conversion']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000017', 'Magnetic Declination', 'The angle between magnetic north and true (geographic) north at a location. With east declination, True = Magnetic + declination; with west, subtract.', 'Magnetic vs true north.', NULL, NULL, NULL, ARRAY['declination','magnetic','true north']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000018', 'Slope to Horizontal (Zenith)', 'Convert a slope distance to horizontal using the zenith angle: H = S·sin(Z).', 'S times sin of the zenith angle.', NULL, NULL, NULL, ARRAY['slope distance','horizontal','zenith']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb038000-0000-0000-0000-000000000019', 'Slope to Horizontal (Vertical Angle)', 'Convert a slope distance to horizontal using the vertical angle: H = S·cos(α).', 'S times cos of the vertical angle.', NULL, NULL, NULL, ARRAY['slope distance','horizontal','vertical angle']::text[], ARRAY['fs-flashcards','fs-m3']::text[], 'fs:f5000003-0000-0000-0000-000000000003', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000001', 'Traverse Types', 'Open (no closure check), closed-loop (returns to its start), and closed-connecting/link (runs between two separately known points).', 'Open, loop, or link.', NULL, NULL, NULL, ARRAY['traverse','open','closed']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000002', 'Latitude of a Course', 'The north–south component of a course: Lat = L·cos(Az). North is positive, south negative.', 'L·cos(azimuth).', NULL, NULL, NULL, ARRAY['latitude','course','traverse']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000003', 'Departure of a Course', 'The east–west component of a course: Dep = L·sin(Az). East is positive, west negative.', 'L·sin(azimuth).', NULL, NULL, NULL, ARRAY['departure','course','traverse']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000004', 'Linear Misclosure', 'The gap when a closed traverse fails to close perfectly: e = √((ΣLat)² + (ΣDep)²).', 'Root-sum-square of ΣLat and ΣDep.', NULL, NULL, NULL, ARRAY['misclosure','traverse','closure']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000005', 'Relative Precision (Traverse)', 'A quality measure: RP = perimeter / linear misclosure, reported as 1 : RP (e.g., 1:10,000).', 'Perimeter ÷ misclosure.', NULL, NULL, NULL, ARRAY['relative precision','traverse']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000006', 'Compass (Bowditch) Rule', 'Distributes traverse misclosure to each course in proportion to its length: C_lat,i = −(ΣLat)·(Lᵢ/perimeter), and similarly for departures. Assumes angles and distances are equally reliable.', 'Correct in proportion to course length.', NULL, NULL, NULL, ARRAY['Bowditch','compass rule','adjustment']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000007', 'Transit Rule', 'Distributes misclosure in proportion to the absolute latitude/departure of each course: C_lat,i = −(ΣLat)·(|Latᵢ|/Σ|Lat|). Favored when angles are more reliable than distances.', 'Correct in proportion to |lat|/|dep|.', NULL, NULL, NULL, ARRAY['transit rule','adjustment','traverse']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000008', 'Polar → Rectangular (P→R)', 'Converting a distance and azimuth into rectangular components (latitude/departure or ΔN/ΔE): ΔN = L·cos(Az), ΔE = L·sin(Az).', 'Distance & bearing → ΔN, ΔE.', NULL, NULL, NULL, ARRAY['polar to rectangular','P to R','coordinates']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000009', 'Rectangular → Polar (R→P) / Inverse', 'From two coordinates get the connecting distance and direction: D = √(ΔN² + ΔE²), Az = atan2(ΔE, ΔN) normalized to 0–360°. This is the "inverse" problem.', 'ΔN, ΔE → distance & azimuth.', NULL, NULL, NULL, ARRAY['inverse','R to P','coordinates']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000010', 'Forward Coordinate Computation', 'Compute the next point from a known point, a distance, and an azimuth: N₂ = N₁ + L·cos(Az); E₂ = E₁ + L·sin(Az).', 'Add the lat/dep to the known N/E.', NULL, NULL, NULL, ARRAY['forward computation','coordinates','traverse']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000011', 'Azimuth ↔ Bearing', 'Quadrant conversions: NE Az = β; SE Az = 180 − β; SW Az = 180 + β; NW Az = 360 − β (β = the bearing angle).', 'Depends on the quadrant.', NULL, NULL, NULL, ARRAY['azimuth','bearing','quadrant']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000012', 'Angle Balancing', 'Before computing a closed traverse, adjust the observed interior angles so they sum to (n − 2)·180°, distributing the angular misclosure equally.', 'Interior angles sum to (n−2)·180°.', NULL, NULL, NULL, ARRAY['angle balancing','interior angles','adjustment']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000013', 'Bearing-Bearing Intersection', 'Locating an unknown point from two known points and the bearing (direction) from each — a classic COGO intersection.', 'Two points, two directions.', NULL, NULL, NULL, ARRAY['intersection','bearing','COGO']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000014', 'Distance-Distance Intersection', 'Locating an unknown point from two known points and the distance (radius) from each; the two circles intersect at the solution(s).', 'Two points, two distances.', NULL, NULL, NULL, ARRAY['intersection','distance','COGO']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000015', 'Area by Coordinates (Shoelace)', 'Area of a closed polygon from its vertex coordinates: A = ½·|Σ Xᵢ(Y_{i+1} − Y_{i−1})|. List vertices in order and wrap around.', 'Cross-multiply the coordinates and halve.', NULL, NULL, NULL, ARRAY['area','coordinates','shoelace']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb048000-0000-0000-0000-000000000016', 'Perimeter', 'The total length of all courses in a traverse; used in relative precision (perimeter/e) and Bowditch adjustment (length-weighting).', 'Sum of all course lengths.', NULL, NULL, NULL, ARRAY['perimeter','traverse']::text[], ARRAY['fs-flashcards','fs-m4']::text[], 'fs:f5000004-0000-0000-0000-000000000004', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000001', 'Area by Coordinates (Shoelace)', 'Polygon area from coordinates: A = ½·|Σ Xᵢ(Y_{i+1} − Y_{i−1})|. Also called the coordinate or cross-product method.', 'Half the sum of the cross products.', NULL, NULL, NULL, ARRAY['area','coordinates','shoelace']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000002', 'DMD Method', 'Double Meridian Distance: computes area from latitudes and meridian distances, A = ½·Σ(DMD·Lat). A traditional hand-computation alternative to coordinates.', 'Area = ½ Σ(DMD × latitude).', NULL, NULL, NULL, ARRAY['DMD','area','method']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000003', 'Trapezoidal Rule', 'Area under a boundary from equally spaced offsets: A = w·[(h₁ + hₙ)/2 + h₂ + h₃ + … + hₙ₋₁], with w the common spacing.', 'Average the ends, add the middles, times width.', NULL, NULL, NULL, ARRAY['trapezoidal rule','offsets','area']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000004', 'Simpson''s 1/3 Rule', 'A more accurate offset-area rule for curved boundaries: A = (w/3)·[h₁ + hₙ + 4·Σ(odd) + 2·Σ(even)]. Requires an even number of intervals (odd number of offsets).', 'Ends + 4×odds + 2×evens, times w/3.', NULL, NULL, NULL, ARRAY['Simpsons rule','area','offsets']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000005', 'Acres from Square Feet', 'Convert area to acres: acres = A(ft²) / 43,560. One acre = 43,560 ft².', 'Divide ft² by 43,560.', NULL, NULL, NULL, ARRAY['acres','area','conversion']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000006', 'Average End Area Volume', 'Earthwork volume between two cross-sections: V = L·(A₁ + A₂)/2, where L is the distance between the end areas.', 'Average the end areas × length.', NULL, NULL, NULL, ARRAY['average end area','volume','earthwork']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000007', 'Prismoidal Formula', 'A more accurate earthwork volume using the middle section: V = L·(A₁ + 4·Aₘ + A₂)/6. Aₘ is the area of the cross-section midway between the ends.', 'Weights the middle area ×4.', NULL, NULL, NULL, ARRAY['prismoidal','volume','earthwork']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000008', 'Cubic Yards', 'Convert earthwork volume from cubic feet to cubic yards: V(yd³) = V(ft³) / 27 (since 1 yd³ = 27 ft³).', 'Divide ft³ by 27.', NULL, NULL, NULL, ARRAY['cubic yards','volume','conversion']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000009', 'Shrinkage & Swell', 'Soil changes volume when moved: it swells when excavated (loose > bank) and shrinks when compacted (compacted < bank). Adjust volumes by the shrinkage/swell factor.', 'Bank, loose, and compacted volumes differ.', NULL, NULL, NULL, ARRAY['shrinkage','swell','earthwork']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000010', 'Degree of Curve (Arc Definition)', 'The central angle subtending a 100-ft arc: D = 5,729.58 / R. Larger D means a sharper (smaller-radius) curve.', '5,729.58 ÷ R.', NULL, NULL, NULL, ARRAY['degree of curve','arc definition','horizontal curve']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000011', 'Radius from Degree of Curve', 'Invert the arc definition: R = 5,729.58 / D.', '5,729.58 ÷ D.', NULL, NULL, NULL, ARRAY['radius','degree of curve']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000012', 'Tangent Distance (T)', 'Distance from the PI (point of intersection) to the PC or PT of a horizontal curve: T = R·tan(I/2), with I the deflection/central angle.', 'R·tan(I/2).', NULL, NULL, NULL, ARRAY['tangent distance','horizontal curve']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000013', 'Curve Length (L)', 'Arc length of a horizontal curve: L = R·I·(π/180) = (I/D)·100.', 'R·I in radians.', NULL, NULL, NULL, ARRAY['curve length','horizontal curve']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000014', 'Long Chord (LC)', 'Straight-line distance from PC to PT: LC = 2R·sin(I/2).', '2R·sin(I/2).', NULL, NULL, NULL, ARRAY['long chord','horizontal curve']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000015', 'Middle Ordinate (M)', 'Distance from the midpoint of the long chord to the midpoint of the curve: M = R·[1 − cos(I/2)].', 'R·(1 − cos(I/2)).', NULL, NULL, NULL, ARRAY['middle ordinate','horizontal curve']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000016', 'External Distance (E)', 'Distance from the PI to the midpoint of the curve: E = R·[sec(I/2) − 1] = R·[1/cos(I/2) − 1].', 'R·(sec(I/2) − 1).', NULL, NULL, NULL, ARRAY['external distance','horizontal curve']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000017', 'Curve Stationing (PC / PT)', 'Locate curve points by station: PC = PI − T, and PT = PC + L (note PT is measured along the curve, not through the PI).', 'PC = PI − T; PT = PC + L.', NULL, NULL, NULL, ARRAY['stationing','PC','PT','curve']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000018', 'Vertical (Parabolic) Curve Elevation', 'Elevation on a vertical curve at distance x from the PVC: Y = Y_PVC + g₁·x + [(g₂ − g₁)/(2L)]·x², where g₁, g₂ are grades and L the curve length.', 'Tangent grade + parabolic term.', NULL, NULL, NULL, ARRAY['vertical curve','parabola','elevation']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb058000-0000-0000-0000-000000000019', 'High / Low Point of a Vertical Curve', 'The turning point occurs where the grade is zero, at x_m = −g₁·L/(g₂ − g₁) measured from the PVC.', 'Where the slope becomes zero.', NULL, NULL, NULL, ARRAY['high point','low point','vertical curve']::text[], ARRAY['fs-flashcards','fs-m5']::text[], 'fs:f5000005-0000-0000-0000-000000000005', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000001', 'GNSS Constellations', 'The global satellite systems: GPS (US), GLONASS (Russia), Galileo (EU), and BeiDou (China). Using more constellations improves satellite availability and geometry.', 'GPS, GLONASS, Galileo, BeiDou.', NULL, NULL, NULL, ARRAY['GNSS','constellation','GPS']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000002', 'Autonomous Positioning', 'A single receiver computing position with no corrections — the least accurate mode (meter-level).', 'One receiver, no corrections.', NULL, NULL, NULL, ARRAY['autonomous','positioning','GNSS']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000003', 'DGPS (Differential)', 'Uses a base station at a known point to compute and broadcast corrections that cancel errors common to nearby rovers — sub-meter accuracy.', 'Base station broadcasts corrections.', NULL, NULL, NULL, ARRAY['DGPS','differential','base']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000004', 'Static GNSS', 'Long occupation of fixed points with carrier-phase data, post-processed for the highest accuracy — the method for control networks.', 'Long occupation, post-processed, control-grade.', NULL, NULL, NULL, ARRAY['static','GNSS','control']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000005', 'RTK (Real-Time Kinematic)', 'Carrier-phase base–rover positioning with a real-time data link (radio/cell) giving centimeter positions instantly in the field.', 'Cm accuracy, real time, base + rover.', NULL, NULL, NULL, ARRAY['RTK','real-time','carrier phase']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000006', 'PPK (Post-Processed Kinematic)', 'Like RTK, but the base–rover corrections are applied later in software instead of over a real-time link — useful when no radio/cell link exists.', 'RTK computed after the fact.', NULL, NULL, NULL, ARRAY['PPK','post-processed']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000007', 'OPUS / PPP', 'Online Positioning User Service / Precise Point Positioning — submit a static occupation (or use precise orbits & clocks) to get cm-level coordinates without a local base station.', 'Precise positioning without your own base.', NULL, NULL, NULL, ARRAY['OPUS','PPP','positioning']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000008', 'RTN / VRS', 'Real-Time Network / Virtual Reference Station: a network of permanent bases models regional errors and generates a virtual base right beside the rover.', 'A network makes a virtual base near you.', NULL, NULL, NULL, ARRAY['RTN','VRS','network']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000009', 'GNSS Error Sources', 'Ionospheric and tropospheric delay, multipath, satellite clock and ephemeris (orbit) errors, and receiver noise all degrade GNSS positions.', 'Atmosphere, multipath, clocks, orbits.', NULL, NULL, NULL, ARRAY['error sources','GNSS','ionosphere']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000010', 'Multipath', 'Error caused by the signal reflecting off buildings, water, or ground before reaching the antenna, corrupting the measured range. Avoid reflective surfaces and use choke-ring antennas.', 'Reflected signals reach the antenna.', NULL, NULL, NULL, ARRAY['multipath','error','GNSS']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000011', 'Dilution of Precision (DOP)', 'A number describing how satellite geometry amplifies ranging error into position error. Well-spread satellites give low (good) DOP.', 'Lower = better geometry.', NULL, NULL, NULL, ARRAY['DOP','geometry','precision']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000012', 'Position Error from DOP', 'Expected position error = user-equivalent range error times the geometry factor: σ_pos = UERE × DOP.', 'σ = UERE × DOP.', NULL, NULL, NULL, ARRAY['DOP','UERE','position error']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000013', 'Orthometric / Ellipsoidal / Geoid Height', 'Heights relate by H = h − N: orthometric height (H, from the geoid) = ellipsoidal height (h, GNSS) − geoid height (N).', 'H = h − N.', NULL, NULL, NULL, ARRAY['orthometric','ellipsoid','geoid']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000014', 'Geoid Undulation (N)', 'The vertical separation between the geoid (mean-sea-level equipotential surface) and the reference ellipsoid at a point. A geoid model supplies N.', 'Geoid-minus-ellipsoid separation.', NULL, NULL, NULL, ARRAY['geoid','undulation','N']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000015', 'Datums (NAD83 / WGS84 / GRS80 / NAVD88)', 'NAD83 and WGS84 are horizontal datums; GRS80 is the reference ellipsoid; NAVD88 is the vertical datum for orthometric heights.', 'Horizontal, ellipsoid, and vertical references.', NULL, NULL, NULL, ARRAY['datum','NAD83','NAVD88']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000016', 'Lambert vs Transverse Mercator', 'State Plane projections: Lambert Conformal Conic suits zones long east–west; Transverse Mercator suits zones long north–south.', 'Lambert = E-W zones; TM = N-S zones.', NULL, NULL, NULL, ARRAY['Lambert','Transverse Mercator','projection']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000017', 'State Plane Coordinate System', 'A projected plane-coordinate grid dividing each state into zones sized to keep distortion within about 1:10,000.', 'Low-distortion plane grid by zone.', NULL, NULL, NULL, ARRAY['SPCS','state plane','zone']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000018', 'Elevation Factor', 'Reduces a ground distance to the ellipsoid: EF = R/(R + h), with R ≈ 20,906,000 ft. Higher elevations give a smaller factor.', 'R/(R+h).', NULL, NULL, NULL, ARRAY['elevation factor','grid','ground']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000019', 'Combined (Grid) Factor', 'Converts ground to grid: CSF = scale factor × elevation factor, so D_grid = D_ground × CSF (and D_ground = D_grid / CSF).', 'Scale factor × elevation factor.', NULL, NULL, NULL, ARRAY['combined factor','grid to ground','CSF']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb068000-0000-0000-0000-000000000020', 'Convergence (Mapping Angle γ)', 'The angle between grid north and geodetic (true) north on a projection; it relates grid and geodetic azimuths: Az_grid = Az_geodetic − γ + (t−T).', 'Grid north vs geodetic north.', NULL, NULL, NULL, ARRAY['convergence','mapping angle','azimuth']::text[], ARRAY['fs-flashcards','fs-m6']::text[], 'fs:f5000006-0000-0000-0000-000000000006', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000001', 'PLSS', 'The Public Land Survey System — the rectangular framework of principal meridians and base lines dividing federal land into townships, ranges, and sections.', 'The rectangular township/section system.', NULL, NULL, NULL, ARRAY['PLSS','public land','rectangular']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000002', 'Township (PLSS)', 'A 6-mile × 6-mile block of 36 sections, located by township number (N/S of a base line) and range number (E/W of a principal meridian).', '6×6 miles, 36 sections.', NULL, NULL, NULL, ARRAY['township','range','PLSS']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000003', 'Section', 'A one-square-mile unit of the PLSS containing 640 acres. A township holds 36 sections.', '1 sq mile = 640 acres.', NULL, NULL, NULL, ARRAY['section','640 acres','PLSS']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000004', 'Section Numbering', 'Sections are numbered 1–36 in a serpentine (boustrophedon) path: Section 1 in the NE corner, west to 6, drop south, east to 12, and so on, ending at 36 in the SE.', 'Starts at 1 in the NE, snakes to 36 in the SE.', NULL, NULL, NULL, ARRAY['section numbering','township']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000005', 'Aliquot Parts', 'The legal subdivision of a section by successive halves and quarters, e.g. the SW¼ of the NE¼. Read them right-to-left to locate the parcel.', 'Halves and quarters of a section.', NULL, NULL, NULL, ARRAY['aliquot','subdivision','section']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000006', 'Quarter Section', 'One quarter of a section: ¼ × 640 = 160 acres.', '160 acres.', NULL, NULL, NULL, ARRAY['quarter section','160 acres']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000007', 'Quarter-Quarter (Forty)', 'A quarter of a quarter-section: ¼ × ¼ × 640 = 40 acres — the classic "forty."', '40 acres.', NULL, NULL, NULL, ARRAY['forty','quarter-quarter','acres']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000008', 'Existent / Obliterated / Lost Corner', 'Existent = position still provable by evidence; Obliterated = no physical trace but recoverable from other evidence/testimony; Lost = not recoverable from evidence, must be re-established by proportionate measurement.', 'Provable, recoverable, or must be restored.', NULL, NULL, NULL, ARRAY['lost corner','obliterated','existent']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000009', 'Single Proportionate Measurement', 'Restores a lost corner that lies on a single line by distributing the measurement discrepancy in proportion to the original record distances between existing corners.', 'Proportion along one line.', NULL, NULL, NULL, ARRAY['single proportion','lost corner','restoration']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000010', 'Double Proportionate Measurement', 'Restores a lost corner controlled in two directions (a latitudinal and a longitudinal line) by proportioning from four surrounding existing corners.', 'Proportion in two directions from four corners.', NULL, NULL, NULL, ARRAY['double proportion','lost corner']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000011', 'Metes-and-Bounds', 'A boundary description that walks the perimeter by courses (bearings and distances) and calls to monuments, starting and closing at a Point of Beginning.', 'Directions and distances around the perimeter.', NULL, NULL, NULL, ARRAY['metes and bounds','description']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000012', 'Footsteps of the Original Surveyor', 'The retracing surveyor’s duty is to follow the evidence and intent of the ORIGINAL survey — not to make a "better" resurvey. Original monuments control.', 'Retrace intent; original monuments control.', NULL, NULL, NULL, ARRAY['footsteps','retracement','original survey']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000013', 'Priority (Dignity) of Calls', 'Order for resolving conflicting calls: natural monuments > artificial monuments > adjoiners (record) > courses (bearings) > distances > area/coordinates. Higher-dignity calls control.', 'Monuments beat bearings beat distances beat area.', NULL, NULL, NULL, ARRAY['priority of calls','dignity','monuments']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000014', 'Senior vs Junior Rights', 'In sequential conveyances, the earlier (senior) deed is superior; the later (junior) grantee takes only what remains and absorbs any excess or deficiency.', 'First deed wins; last bears the leftover.', NULL, NULL, NULL, ARRAY['senior rights','junior rights','conveyance']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000015', 'Accretion / Reliction / Erosion / Avulsion', 'Accretion = gradual deposit of soil (adds land); reliction = gradual water recession exposing land; erosion = gradual loss; avulsion = sudden change — with avulsion the boundary does NOT move.', 'Gradual moves the line; avulsion does not.', NULL, NULL, NULL, ARRAY['accretion','avulsion','riparian']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000016', 'Adverse Possession', 'Gaining title by possession that is Open, Notorious, Exclusive, Continuous, and Hostile for the statutory period (often also actual and under claim of right).', 'Open, notorious, exclusive, continuous, hostile.', NULL, NULL, NULL, ARRAY['adverse possession','title','elements']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000017', 'Recording Acts', 'Statutes (notice, race, race-notice) that decide priority among competing claims to the same land and protect the Bona Fide Purchaser (BFP) who buys for value without notice.', 'Notice / race / race-notice; protects the BFP.', NULL, NULL, NULL, ARRAY['recording acts','BFP','notice']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000018', 'Easement Types', 'Express (created in writing), implied (by prior use or necessity), and prescriptive (acquired by long adverse use, like adverse possession but for a use rather than title).', 'Express, implied, prescriptive.', NULL, NULL, NULL, ARRAY['easement','prescriptive','implied']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000019', 'Texas Vara', 'Texas uses no PLSS grid — original GLO surveys/abstracts and the vara: 1 vara = 33⅓ in = 2.7778 ft.', '1 vara ≈ 2.7778 ft.', NULL, NULL, NULL, ARRAY['vara','Texas','GLO']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb078000-0000-0000-0000-000000000020', 'Section Acreage Cheat-Sheet', '1 section = 640 ac; ¼ section = 160 ac; half of a quarter = 80 ac; quarter-quarter (forty) = 40 ac. 1 acre = 43,560 ft² = 10 sq chains.', '640 / 160 / 80 / 40.', NULL, NULL, NULL, ARRAY['acreage','section','aliquot']::text[], ARRAY['fs-flashcards','fs-m7']::text[], 'fs:f5000007-0000-0000-0000-000000000007', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000001', 'Vertical Photo Scale', 'The scale of a vertical aerial photo: S = f/(H − h), where f is focal length, H flying height above datum, and h the ground elevation.', 'f / (H − h).', NULL, NULL, NULL, ARRAY['photo scale','photogrammetry']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000002', 'Average Photo Scale', 'Because terrain varies, a representative scale is computed at the average ground elevation: S = f/(H − h_avg).', 'Use average terrain elevation.', NULL, NULL, NULL, ARRAY['average scale','photo']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000003', 'Ground Distance from a Photo', 'Convert a measured photo distance to ground: D_ground = d_photo/S = d_photo·(H − h)/f.', 'Photo distance ÷ scale.', NULL, NULL, NULL, ARRAY['ground distance','photo','scale']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000004', 'Ground Sample Distance (GSD)', 'The ground size represented by one pixel: GSD = (pixel_size · H)/f. Smaller GSD means higher-resolution imagery.', 'Ground size of one pixel.', NULL, NULL, NULL, ARRAY['GSD','resolution','pixel']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000005', 'Relief (Radial) Displacement', 'On a vertical photo, tall features lean radially outward from the principal point: d = r·h/H (r = radial distance, h = object height, H = flying height).', 'd = r·h/H, outward from center.', NULL, NULL, NULL, ARRAY['relief displacement','radial','photo']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000006', 'Flying Height', 'The camera height above the ground for a given scale: H − h = f/S.', 'f / S above the ground.', NULL, NULL, NULL, ARRAY['flying height','photo scale']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000007', 'Overlap & Sidelap', 'Forward overlap (~60%) along a flight line provides stereo coverage; sidelap (~30%) between adjacent lines ensures no gaps.', '≈60% forward, ≈30% side.', NULL, NULL, NULL, ARRAY['overlap','sidelap','flight line']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000008', 'Parallax', 'The apparent shift of a point between two overlapping photos. Greater parallax means a higher/closer point; parallax differences yield elevations.', 'Apparent shift → height.', NULL, NULL, NULL, ARRAY['parallax','stereo','height']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000009', 'Stereo Model', 'Two overlapping photos viewed together form a three-dimensional model that can be measured for position and elevation.', 'Overlapping pair → a 3D model.', NULL, NULL, NULL, ARRAY['stereo model','overlap','3D']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000010', 'LiDAR', 'Light Detection and Ranging — an active sensor that measures distance by timing laser pulses, producing dense 3D point clouds of terrain and features.', 'Laser pulses → 3D point cloud.', NULL, NULL, NULL, ARRAY['LiDAR','point cloud','remote sensing']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000011', 'Multispectral Imagery', 'Imagery captured in several wavelength bands (visible plus near-/thermal-infrared) used to classify land cover and vegetation in remote sensing.', 'Multiple wavelength bands.', NULL, NULL, NULL, ARRAY['multispectral','remote sensing','bands']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000012', 'UAS / Drone Mapping', 'Small unmanned aircraft collect highly overlapping imagery that photogrammetric software turns into orthomosaics, DSMs, and 3D models.', 'Drones → orthomosaics and 3D models.', NULL, NULL, NULL, ARRAY['UAS','drone','mapping']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000013', 'Vector vs Raster', 'Vector data represents features as points, lines, and polygons with coordinates; raster data is a grid of cells/pixels (imagery, DEMs).', 'Points/lines/polygons vs a grid of cells.', NULL, NULL, NULL, ARRAY['vector','raster','GIS']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000014', 'Contours', 'Map lines connecting points of equal elevation. The contour interval is the constant vertical distance between adjacent contours.', 'Lines of equal elevation.', NULL, NULL, NULL, ARRAY['contours','contour interval','elevation']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000015', 'Orthophoto', 'An aerial image that has been orthorectified to remove tilt and relief distortion, giving uniform scale so it can be measured like a map.', 'Distortion-corrected, map-accurate image.', NULL, NULL, NULL, ARRAY['orthophoto','orthorectified','GIS']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000016', 'Metadata', 'Data about the data — projection, datum, accuracy, source, and date — essential for using GIS layers correctly.', 'Projection, datum, accuracy, source.', NULL, NULL, NULL, ARRAY['metadata','GIS']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000017', 'Construction Stakeout', 'Placing stakes from design coordinates to mark line, grade, and offset so contractors can build to the plans.', 'Stake line, grade, and offset.', NULL, NULL, NULL, ARRAY['stakeout','construction','layout']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000018', 'Offset Stake', 'A stake set a known horizontal distance from the actual line/feature (so it survives excavation), marked with the cut or fill to grade.', 'Set off the line, marked cut/fill.', NULL, NULL, NULL, ARRAY['offset','stake','cut fill']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000019', 'Cut and Fill', 'Cut = excavate material where the ground is above design grade; Fill = add material where it is below grade.', 'Cut above grade, fill below.', NULL, NULL, NULL, ARRAY['cut','fill','earthwork']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb088000-0000-0000-0000-000000000020', 'Grade (Slope)', 'Steepness expressed as a percent: grade % = (ΔElev / horizontal distance) × 100.', 'Rise/run × 100.', NULL, NULL, NULL, ARRAY['grade','slope','percent']::text[], ARRAY['fs-flashcards','fs-m8']::text[], 'fs:f5000008-0000-0000-0000-000000000008', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000001', 'Approved Calculators (NCEES)', 'Only specific non-programmable models are allowed: Casio fx-115/991, HP 33s/35s, and TI-30X/36X. Graphing and programmable calculators are barred.', 'Casio 115/991, HP 33s/35s, TI-30X/36X.', NULL, NULL, NULL, ARRAY['calculator','NCEES','approved']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000002', 'DMS Entry & Arithmetic', 'Use the calculator’s degree°′″ key to enter angles and add/subtract them directly, avoiding manual decimal conversion and its rounding errors.', 'Use the °′″ key directly.', NULL, NULL, NULL, ARRAY['DMS','calculator','angles']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000003', 'DMS ↔ Decimal Degrees', 'dec = D + M/60 + S/3600. The °′″ and ▸DMS keys convert both ways in one keystroke.', 'Minutes/60 + seconds/3600.', NULL, NULL, NULL, ARRAY['DMS','decimal degrees','conversion']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000004', 'R▸P (Rectangular → Polar)', 'One operation converts ΔN, ΔE into distance and azimuth — the calculator’s built-in inverse-COGO engine.', 'ΔN, ΔE → distance & azimuth.', NULL, NULL, NULL, ARRAY['R to P','inverse','COGO']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000005', 'P▸R (Polar → Rectangular)', 'Converts a distance and azimuth into components ΔN = D·cos(Az) and ΔE = D·sin(Az) — the forward-COGO engine.', 'Distance & azimuth → ΔN, ΔE.', NULL, NULL, NULL, ARRAY['P to R','forward','COGO']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000006', 'Inverse via R▸P', 'Between two coordinates: distance D = √(ΔN² + ΔE²) and azimuth Az = atan2(ΔE, ΔN), obtained in a single R▸P operation.', 'Distance & azimuth in one step.', NULL, NULL, NULL, ARRAY['inverse','R to P','coordinates']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000007', 'Forward via P▸R', 'Locate a new point: N₂ = N₁ + D·cos(Az), E₂ = E₁ + D·sin(Az).', 'Add D·cos and D·sin to the start.', NULL, NULL, NULL, ARRAY['forward','P to R','coordinates']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000008', 'atan2 vs atan', 'atan2(ΔE, ΔN) returns the correct 0–360° quadrant automatically; a plain arctangent loses the quadrant and must be fixed by inspection.', 'atan2 keeps the quadrant.', NULL, NULL, NULL, ARRAY['atan2','azimuth','quadrant']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000009', 'Back-Azimuth (calculator)', 'Az_back = (Az + 180) mod 360 — add 180° and wrap around at 360°.', '(Az + 180) mod 360.', NULL, NULL, NULL, ARRAY['back azimuth','calculator']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000010', 'Bearing → Azimuth Quadrants', 'NE: Az = β; SE: Az = 180 − β; SW: Az = 180 + β; NW: Az = 360 − β (β is the bearing angle).', 'Depends on the quadrant.', NULL, NULL, NULL, ARRAY['bearing','azimuth','quadrant']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000011', 'Memory Registers (STO/RCL/SUM)', 'Store coordinates and running sums in memory to chain a traverse without re-keying values — faster and far less error-prone.', 'Store/recall to chain computations.', NULL, NULL, NULL, ARRAY['memory','STO','RCL']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000012', 'Statistics Mode', 'Enter a data list in the calculator’s stats mode to read out the mean and sample standard deviation directly for error/precision problems.', 'Get mean and σ from a data list.', NULL, NULL, NULL, ARRAY['statistics mode','standard deviation','calculator']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000013', 'DEG vs RAD Mode', 'Keep the calculator in DEGREE mode for surveying angle work. A wrong angle mode is a classic silent error that ruins trig results.', 'Stay in DEG for angles.', NULL, NULL, NULL, ARRAY['degrees','radians','mode']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000014', 'Area by Coordinates (calculator)', 'Accumulate the cross-products (Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ) with the SUM register around the polygon, then halve the absolute value: A = ½·|Σ|.', 'Sum cross-products, halve the absolute value.', NULL, NULL, NULL, ARRAY['area','coordinates','shoelace']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000015', 'Curve Quickies', 'Under time pressure recall the two fastest curve equations: T = R·tan(I/2) and L = R·I·(π/180).', 'T = R·tan(I/2); L = R·I in radians.', NULL, NULL, NULL, ARRAY['curve','tangent','length']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000016', 'FS Exam Time Budget', 'About 2.9 minutes per question — 110 questions in 5 hours 20 minutes. Keep pace and do not stall on one item.', '≈ 2.9 min/question.', NULL, NULL, NULL, ARRAY['time budget','FS exam','pacing']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000017', 'Flag-and-Return', 'Answer the easy questions first, flag the hard ones, and come back with your remaining time. Never leave a blank — there is no wrong-answer penalty.', 'Skip hard ones, return later; never blank.', NULL, NULL, NULL, ARRAY['flag and return','strategy','guessing']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb098000-0000-0000-0000-000000000018', 'Efficient Handbook Search', 'The FS exam is closed-book except the electronic FS Reference Handbook. Know which section holds each formula so you find it in seconds, not minutes.', 'Know where each formula lives.', NULL, NULL, NULL, ARRAY['reference handbook','search','strategy']::text[], ARRAY['fs-flashcards','fs-m9']::text[], 'fs:f5000009-0000-0000-0000-000000000009', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000001', 'FS Exam Format', '110 questions, 5 hours 20 minutes, computer-based (CBT) at a Pearson VUE center. Closed-book except for the searchable electronic FS Reference Handbook.', '110 questions, 5h20m, CBT, handbook only.', NULL, NULL, NULL, ARRAY['FS exam','format','CBT']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000002', 'Seven Knowledge Areas', 'The FS exam spans: math/stats, field & office processes, geodesy/principles, computations, mapping/photogrammetry, boundary law, and business/ethics.', 'From math to boundary law to ethics.', NULL, NULL, NULL, ARRAY['knowledge areas','FS exam','topics']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000003', 'Category Weighting', 'Boundary law is the single heaviest area, followed by computations. Weight your study time toward the heaviest categories.', 'Boundary law heaviest, then computations.', NULL, NULL, NULL, ARRAY['weighting','category','study plan']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000004', 'Priority (Dignity) of Calls', 'The controlling hierarchy of boundary evidence: natural monuments > artificial monuments > adjoiners > courses (bearings) > distances > area/coordinates.', 'Monuments over bearings over distances over area.', NULL, NULL, NULL, ARRAY['priority of calls','boundary','evidence']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000005', 'Recall: Standard Error of the Mean', 'σ_m = σ / √n — the uncertainty of a computed mean shrinks with the square root of the number of observations.', 'σ / √n.', NULL, NULL, NULL, ARRAY['standard error','mean','statistics']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000006', 'Recall: Error Propagation (sum)', 'σ_sum = √(σ₁² + σ₂² + … + σₙ²) — independent random errors combine in quadrature.', 'Root-sum-square.', NULL, NULL, NULL, ARRAY['error propagation','sum','statistics']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000007', 'Recall: Differential Leveling', 'HI = Elev + BS; Elev = HI − FS. Backsight up to the instrument, foresight down to the point.', 'HI = Elev + BS; Elev = HI − FS.', NULL, NULL, NULL, ARRAY['leveling','HI','BS','FS']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'beginner', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000008', 'Recall: Latitude & Departure', 'Lat = L·cos(Az); Dep = L·sin(Az) — the N–S and E–W components of a course.', 'cos for lat, sin for dep.', NULL, NULL, NULL, ARRAY['latitude','departure','traverse']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000009', 'Recall: Misclosure & Precision', 'misclose = √(ΣLat² + ΣDep²); relative precision = perimeter / misclose (reported 1:RP).', 'RSS of ΣLat, ΣDep; perimeter/misclose.', NULL, NULL, NULL, ARRAY['misclosure','precision','traverse']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000010', 'Recall: Inverse', 'Between two coordinates: D = √(ΔN² + ΔE²) and Az = atan2(ΔE, ΔN) reduced to 0–360°.', 'Distance and azimuth from ΔN, ΔE.', NULL, NULL, NULL, ARRAY['inverse','distance','azimuth']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000011', 'Recall: Area by Coordinates', 'A = ½·|Σ (Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)| — the shoelace/coordinate method.', 'Half the absolute cross-product sum.', NULL, NULL, NULL, ARRAY['area','coordinates','shoelace']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000012', 'Recall: Curve T & L', 'Horizontal curve: tangent T = R·tan(I/2); length L = R·I·(π/180).', 'T = R·tan(I/2); L = R·I in radians.', NULL, NULL, NULL, ARRAY['curve','tangent','length']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000013', 'Recall: Vertical Curve', 'Elevation on a parabolic vertical curve: Y = Y_PVC + g₁·x + [(g₂ − g₁)/(2L)]·x².', 'Tangent grade + parabolic term.', NULL, NULL, NULL, ARRAY['vertical curve','elevation']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000014', 'Recall: Photo Scale & GSD', 'Vertical photo scale S = f/(H − h); ground sample distance GSD = (pixel size · H)/f.', 'S = f/(H−h); GSD = pixel·H/f.', NULL, NULL, NULL, ARRAY['photo scale','GSD','photogrammetry']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000015', 'Recall: Geoid Relationship', 'H = h − N — orthometric height equals ellipsoidal (GNSS) height minus the geoid undulation.', 'H = h − N.', NULL, NULL, NULL, ARRAY['geoid','orthometric','ellipsoid']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'intermediate', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000016', 'Recall: Grid ↔ Ground', 'grid = ground · CF; ground = grid / CF; combined factor CF = scale factor × elevation factor.', 'CF = SF × EF.', NULL, NULL, NULL, ARRAY['grid','ground','combined factor']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000017', 'Multi-Step Problem Flow', 'A frequent exam chain: run a traverse → compute linear misclosure → adjust it (Bowditch) → compute area by coordinates. Practice the whole pipeline, not just pieces.', 'Traverse → misclosure → adjust → area.', NULL, NULL, NULL, ARRAY['multi-step','traverse','problem']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'advanced', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb108000-0000-0000-0000-000000000018', 'Exam-Day Logistics', 'Bring an approved calculator and ID, arrive early, use the provided scratch/whiteboard, and manage the clock with flag-and-return.', 'Calculator, ID, early arrival, pace yourself.', NULL, NULL, NULL, ARRAY['exam day','logistics','strategy']::text[], ARRAY['fs-flashcards','fs-m10']::text[], 'fs:f500000a-0000-0000-0000-00000000000a', 'beginner', true, 'approved');
